+    // Validate required arguments
+    if (this.options.validateArguments && prompt.arguments) {
+      for (const arg of prompt.arguments) {
+        if (arg.required && !(arg.name in args)) {
+          throw new Error(`Missing required argument: ${arg.name}`);
+        }
+      }
+    }
