+  clear(): void {
+    this.tools.clear();
+    this.categoryIndex.clear();
+    this.tagIndex.clear();
+    this.logger.info('Tool registry cleared');
+    this.emit('registry:cleared');
+  }
+}
+
+export function createToolRegistry(logger: ILogger): ToolRegistry {
+  return new ToolRegistry(logger);
+}
+
+export function defineTool<TInput = Record<string, unknown>, TOutput = unknown>(
+  name: string,
+  description: string,
+  inputSchema: JSONSchema,
+  handler: ToolHandler<TInput, TOutput>,
+  options?: {
+    category?: string;
+    tags?: string[];
+    version?: string;
+    deprecated?: boolean;
+    cacheable?: boolean;
+    cacheTTL?: number;
+    timeout?: number;
+  }
+): MCPTool<TInput, TOutput> {
+  return {
+    name,
+    description,
+    inputSchema,
+    handler,
+    ...options,
+  };
+}

