+    return {
+      healthy: this.running,
+      metrics: {
+        messagesReceived: this.messagesReceived,
+        messagesSent: this.messagesSent,
+        errors: this.errors,
+        activeConnections: this.clients.size,
+        totalConnections: this.totalConnections,
