+  | 'session:initialized'
+  | 'session:closed'
+  | 'session:error'
+  | 'tool:registered'
+  | 'tool:unregistered'
+  | 'tool:called'
+  | 'tool:completed'
+  | 'tool:error'
+  | 'transport:connected'
