+  METHOD_NOT_FOUND: -32601,
+  INVALID_PARAMS: -32602,
+  INTERNAL_ERROR: -32603,
+  SERVER_NOT_INITIALIZED: -32002,
+  UNKNOWN_ERROR: -32001,
+  REQUEST_CANCELLED: -32800,
+  RATE_LIMITED: -32000,
+  AUTHENTICATION_REQUIRED: -32001,
+  AUTHORIZATION_FAILED: -32002,
