+
+export class MCPServerError extends Error {
+  constructor(
+    message: string,
+    public code: number = ErrorCodes.INTERNAL_ERROR,
+    public data?: unknown
+  ) {
+    super(message);
+    this.name = 'MCPServerError';
+  }
+
+  toMCPError(): MCPError {
+    return {
+      code: this.code,
+      message: this.message,
+      data: this.data,
+    };
+  }
+}

