+                    promptTokens: inputTokens,
+                    completionTokens: totalOutputTokens,
+                    totalTokens: inputTokens + totalOutputTokens,
+                  },
+                  cost: {
+                    promptCost,
+                    completionCost,
+                    totalCost: promptCost + completionCost,
+                    currency: 'USD',
+                  },
+                };
+              }
+            } catch {
+              // Ignore parse errors
+            }
+          }
+        }
+      }
+    } catch (error) {
+      clearTimeout(timeout);
+      throw this.transformError(error);
+    } finally {
+      clearTimeout(timeout);
+    }
+  }
