+          'openai',
+          retryAfter ? parseInt(retryAfter) : undefined,
+          errorData
+        );
+      case 404:
+        throw new ModelNotFoundError(this.config.model, 'openai', errorData);
+      default:
+        throw new LLMProviderError(
+          message,
+          `OPENAI_${response.status}`,
+          'openai',
+          response.status,
+          response.status >= 500,
+          errorData
+        );
+    }
+  }
+}

